<?php
declare(strict_types=1);

if(!str_starts_with($path,'/admin/ai'))return;
if(!(user()['is_admin']??false)){http_response_code(403);exit('Forbidden');}

function knowledge_extract_text(string $path,string $mime): string {
    if(in_array($mime,['text/plain','text/markdown','text/csv','application/json'],true))return mb_substr((string)file_get_contents($path),0,500000);
    if($mime==='application/vnd.openxmlformats-officedocument.wordprocessingml.document'&&class_exists('ZipArchive')){$zip=new ZipArchive();if($zip->open($path)===true){$xml=(string)$zip->getFromName('word/document.xml');$zip->close();return mb_substr(trim(html_entity_decode(strip_tags(str_replace(['</w:p>','</w:tr>'],["\n","\n"],$xml)),ENT_QUOTES|ENT_XML1,'UTF-8')),0,500000);}}
    if($mime==='application/pdf'){$command='pdftotext '.escapeshellarg($path).' - 2>/dev/null';$text=(string)shell_exec($command);return mb_substr(trim($text),0,500000);}
    return '';
}

if(preg_match('#^/admin/ai/knowledge/(\d+)/download$#',$path,$m)){$stmt=db()->prepare('SELECT stored_name,original_name,mime_type FROM knowledge_base_items WHERE id=? AND item_type=\'file\'');$stmt->execute([(int)$m[1]]);$item=$stmt->fetch();$file=$item?dirname(__DIR__).'/storage/uploads/'.basename((string)$item['stored_name']):'';if(!$item||!is_file($file)){http_response_code(404);exit('File not found');}header('Content-Type: '.$item['mime_type']);header("Content-Disposition: attachment; filename*=UTF-8''".rawurlencode($item['original_name']));header('X-Content-Type-Options: nosniff');readfile($file);exit;}

if($method==='POST'){
    verify_csrf();$action=(string)post('action');
    if($action==='settings'){$values=['openai_model'=>trim((string)post('openai_model'))?:'gpt-5.4-mini'];if(trim((string)post('openai_api_key'))!=='')$values['openai_api_key_enc']=encrypt_secret(trim((string)post('openai_api_key')));$stmt=db()->prepare('INSERT INTO app_settings(setting_key,setting_value) VALUES(?,?) ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value)');foreach($values as $key=>$value)$stmt->execute([$key,$value]);audit('update','ai_settings',null,['model'=>$values['openai_model'],'key_changed'=>isset($values['openai_api_key_enc'])]);flash('success','AI settings saved.');}
    elseif($action==='save_text'){$id=(int)post('item_id');$title=trim((string)post('title'));$body=trim((string)post('body'));if($title===''||$body==='')flash('error','Knowledge title and background information are required.');elseif($id){db()->prepare("UPDATE knowledge_base_items SET title=?,body=?,extracted_text=?,updated_by=? WHERE id=? AND item_type='text'")->execute([$title,$body,$body,user()['id'],$id]);audit('update','knowledge_base_item',$id);}else{db()->prepare("INSERT INTO knowledge_base_items(title,item_type,body,extracted_text,created_by,updated_by) VALUES(?,'text',?,?,?,?)")->execute([$title,$body,$body,user()['id'],user()['id']]);audit('create','knowledge_base_item',(int)db()->lastInsertId());}flash('success','Knowledge entry saved.');}
    elseif($action==='upload'){$title=trim((string)post('title'));$file=$_FILES['knowledge_file']??null;$allowed=['text/plain'=>'txt','text/markdown'=>'md','text/csv'=>'csv','application/json'=>'json','application/pdf'=>'pdf','application/vnd.openxmlformats-officedocument.wordprocessingml.document'=>'docx'];if($title===''||!$file||$file['error']!==UPLOAD_ERR_OK||$file['size']>12*1024*1024){flash('error','Choose a title and a file no larger than 12 MB.');}else{$mime=(new finfo(FILEINFO_MIME_TYPE))->file($file['tmp_name']);if(!isset($allowed[$mime]))flash('error','Knowledge files must be TXT, Markdown, CSV, JSON, PDF, or DOCX.');else{$stored='knowledge-'.bin2hex(random_bytes(20)).'.'.$allowed[$mime];$destination=dirname(__DIR__).'/storage/uploads/'.$stored;if(!move_uploaded_file($file['tmp_name'],$destination))throw new RuntimeException('Knowledge file upload failed.');$text=knowledge_extract_text($destination,$mime);db()->prepare("INSERT INTO knowledge_base_items(title,item_type,stored_name,original_name,mime_type,extracted_text,created_by,updated_by) VALUES(?,'file',?,?,?,?,?,?)")->execute([$title,$stored,basename($file['name']),$mime,$text,user()['id'],user()['id']]);audit('create','knowledge_base_item',(int)db()->lastInsertId(),['file_type'=>$mime,'text_extracted'=>$text!=='']);flash('success',$text!==''?'Knowledge file uploaded and indexed.':'File uploaded; no searchable text could be extracted.');}}}
    elseif($action==='delete'){$id=(int)post('item_id');$stmt=db()->prepare('SELECT stored_name FROM knowledge_base_items WHERE id=?');$stmt->execute([$id]);$stored=$stmt->fetchColumn();db()->prepare('DELETE FROM knowledge_base_items WHERE id=?')->execute([$id]);if($stored){$file=dirname(__DIR__).'/storage/uploads/'.basename((string)$stored);if(is_file($file))unlink($file);}audit('delete','knowledge_base_item',$id);flash('success','Knowledge item deleted.');}
    redirect('/admin/ai');
}

$items=db()->query('SELECT k.*,COALESCE(NULLIF(u.display_name,\'\'),u.username) updated_by_name FROM knowledge_base_items k LEFT JOIN users u ON u.id=k.updated_by ORDER BY k.updated_at DESC')->fetchAll();$settings=app_settings();
layout('AI setup & knowledge base',function()use($items,$settings){?><div class="actions"><h1 style="margin:0">AI setup & knowledge base</h1></div><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="settings"><h2>OpenAI configuration</h2><p class="muted">The API key is encrypted before storage and is never displayed again. Leave the field blank to keep the stored key.</p><div class="form-grid"><label>OpenAI API key<input type="password" name="openai_api_key" autocomplete="new-password" placeholder="<?=$settings['openai_api_key_enc']?'Stored — enter a new key to replace it':'Enter a project API key'?>"></label><label>Model<input name="openai_model" value="<?=e($settings['openai_model'])?>" required><span class="muted">Default: gpt-5.4-mini</span></label></div><button>Save AI settings</button></form><div class="grid"><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="save_text"><h2>Add background information</h2><label>Topic<input name="title" placeholder="Company, product, founder, goals…" required></label><label>Information<textarea name="body" rows="10" required></textarea></label><button>Add to knowledge base</button></form><form class="card" method="post" enctype="multipart/form-data"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="upload"><h2>Upload knowledge file</h2><label>Title<input name="title" required></label><label>File<input type="file" name="knowledge_file" accept=".txt,.md,.csv,.json,.pdf,.docx" required></label><p class="muted">TXT, Markdown, CSV, JSON, PDF, or DOCX; maximum 12 MB. Text is extracted for AI context.</p><button>Upload and index</button></form></div><div class="card"><h2>Knowledge base</h2><div style="overflow:auto"><table><thead><tr><th>Title</th><th>Type</th><th>Indexed text</th><th>Updated</th><th>Actions</th></tr></thead><tbody><?php foreach($items as $item):?><tr><td><?=e($item['title'])?><?php if($item['original_name']):?><br><span class="muted"><?=e($item['original_name'])?></span><?php endif?></td><td><?=e(ucfirst($item['item_type']))?></td><td><?=number_format(mb_strlen((string)$item['extracted_text']))?> characters</td><td><?=e($item['updated_at'])?><br><span class="muted"><?=e($item['updated_by_name'])?></span></td><td><div class="actions"><?php if($item['item_type']==='file'):?><a class="btn compact secondary" href="/admin/ai/knowledge/<?=$item['id']?>/download">Download</a><?php else:?><details><summary class="btn compact secondary">Edit</summary><form method="post" class="card" style="min-width:360px"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="save_text"><input type="hidden" name="item_id" value="<?=$item['id']?>"><label>Topic<input name="title" value="<?=e($item['title'])?>" required></label><label>Information<textarea name="body" rows="8" required><?=e($item['body'])?></textarea></label><button>Update</button></form></details><?php endif?><form method="post" onsubmit="return confirm('Delete this knowledge item?')"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="delete"><input type="hidden" name="item_id" value="<?=$item['id']?>"><button class="compact danger">Delete</button></form></div></td></tr><?php endforeach?></tbody></table></div><?php if(!$items):?><p>No knowledge-base information has been added.</p><?php endif?></div><?php });exit;
